mapper.sql:
select c.customer_id, c.name, c.alias, c.phone, c.contact_name, c.route_id, r.route_name,
       c.debt, c.map_location, c.longitude, c.latitude, c.map_address, c.map_provider, c.photo, c.remark
from (
    select * from biz_customer ${ew.getCustomSqlSegment}
) c
left join biz_route r on c.route_id = r.route_id
